SELECT tam.*
FROM esg.tb_action_master tam -- 추진 목표
WHERE 1 = 1
  AND tam.comp_id = #{compId}
  AND tam.write_year = #{writeYear}

WITH RankedObjectives AS (
    SELECT *,
           ROW_NUMBER() OVER (PARTITION BY action_objective ORDER BY created_at DESC) AS rn
    FROM esg.tb_action_objective_plan
    WHERE comp_id = #{compId}
)
SELECT *
FROM RankedObjectives
WHERE rn = 1;

   SELECT toi.orgn_id, toi.orgn_nm, tap.*
     FROM ESG.tb_action_performance tap
LEFT JOIN esg.tb_orgn_info toi
       ON tap.orgn_id = toi.orgn_id
    WHERE tap.comp_id = #{compId}
      AND tap.write_year = #{writeYear}
      AND tap.doc_type = #{docType}
      AND tap.doc_no = #{docNo}
      AND tap.doc_seq = #{docSeq}

