SELECT *
FROM esg.tb_action_performance
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}
  AND doc_detail_seq = #{docDetailSeq}
  AND doc_performance_seq = #{docPerformanceSeq}

SELECT *
FROM esg.tb_action_performance_detail
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}
  AND doc_detail_seq = #{docDetailSeq}
  AND doc_performance_seq = #{docPerformanceSeq}
  AND doc_performance_detail_seq = #{docPerformanceDetailSeq}

SELECT tapd.*, sf1.file_id
FROM esg.tb_action_performance_detail tapd
         -- 파일 정보 매핑
         LEFT JOIN esg.tb_sys_file sf1 ON sf1.target_id = (tapd.write_year || tapd.doc_no || tapd.doc_seq || tapd.doc_detail_seq || tapd.doc_performance_seq || tapd.doc_performance_detail_seq)
    AND sf1.target_type = #{docType}
    AND sf1.comp_id =  #{compId}
WHERE 1 = 1
  AND tapd.comp_id = #{compId}
  AND tapd.write_year = #{writeYear}
  AND tapd.doc_no = #{docNo}
  AND tapd.doc_type = #{docType}
  AND tapd.doc_seq = #{docSeq}
  AND tapd.doc_detail_seq = #{docDetailSeq}
  AND tapd.doc_performance_seq = #{searchText}
ORDER BY use_yn desc, ord_seq, created_at

SELECT t1.hr_id
    , t2.hr_nm
FROM esg.tb_action_performance_hr t1
LEFT JOIN esg.tb_hr_info t2
    on t1.hr_id = t2.hr_id
WHERE 1 = 1
  AND t1.comp_id = #{compId}
  AND t1.write_year = #{writeYear}
  AND t1.doc_no = #{docNo}
  AND t1.doc_type = #{docType}
  AND t1.doc_seq = #{docSeq}
  AND t1.doc_detail_seq = #{docDetailSeq}
  AND t1.doc_performance_seq = #{docPerformanceSeq}

